function App() {
  const { user, loading } = useAuth();
  const isCallback = window.location.pathname === '/callback';

  if (loading) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <h2>Loading...</h2>
      </div>
    );
  }

  if (isCallback) {
    return <CallbackPage />;
  }

  if (!user) {
    return <LoginPage />;
  }

  return <ProfilePage />;
}

function Root() {
  return (
    <AuthProvider>
      <App />
    </AuthProvider>
  );
}

const container = document.getElementById('root');
const root = createRoot(container);
root.render(<Root />);